import React, { useState } from 'react';
import axios from 'axios';

const KycUpload = ({ onSuccess }) => {
  const [files, setFiles] = useState([]);
  const [status, setStatus] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (files.length === 0) {
      setStatus('Please choose at least one document.');
      return;
    }

    const formData = new FormData();
    files.forEach(file => formData.append('documents', file));

    try {
      const token = localStorage.getItem('token');
      await axios.post('http://localhost:5000/api/kyc/upload', formData, {
        headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'multipart/form-data' }
      });
      setStatus('KYC uploaded successfully.');
      setFiles([]);
      if (onSuccess) onSuccess();
    } catch (error) {
      setStatus(error?.response?.data?.error || 'Upload failed.');
    }
  };

  return (
    <form className="form-grid" onSubmit={handleSubmit}>
      <label>
        Choose documents
        <input type="file" multiple onChange={(e) => setFiles(Array.from(e.target.files))} />
      </label>
      {files.length > 0 && (
        <div className="file-list">
          {files.map((file, index) => (
            <span key={index}>{file.name}</span>
          ))}
        </div>
      )}
      {status && <div className="status-message">{status}</div>}
      <button type="submit">Upload</button>
    </form>
  );
};

export default KycUpload;
